    keyIntensity={15}
    keySoftness={70}
    lightTarget={64}
    seed={42}
    vignette={25}
    wallCurvature={42}
  />
  <Spherize
    depth={1.1}
    lightColor="#a9cbe8"
    lightIntensity={0.3}
    lightPosition={{ x: 0.62, y: 0.01 }}
    lightSoftness={0.2}
